const handleQuoteStep = (
  step: QuoteStep,
  index: number,
  customer: Customer,
  policies: Policy[],
): QuoteResult => {
  policies[index] = createPolicy(step.items);
  return quotePremium(step.items, customer, isFollowUpStep(index));
};

const handleClaimStep = (step: ClaimStep, policies: Policy[]): ClaimResult =>
  processClaim(policies[step.policy], step.incident);

const handleStep = (
  step: Step,
  index: number,
  customer: Customer,
  policies: Policy[],
): StepResult =>
  step.op === "quote"
    ? handleQuoteStep(step, index, customer, policies)
    : handleClaimStep(step, policies);

export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  const results = steps.map((step, index) => handleStep(step, index, customer, policies));
  return { results };
};
